-- Insert 50 throwing-athlete exercises
INSERT INTO coaching.exercise (
  facility_id, name, slug, description, sport_id, skill_level, age_min,
  default_sets, default_reps, default_work_seconds, default_rest_seconds, est_seconds_per_set,
  is_published, visibility,
  card_summary, coach_language, athlete_language,
  movement_family, primary_phase_key, phase_subrole, primary_order_slot,
  movement_requirements, coaching_execution, pairing_logic, media_library
)
SELECT
  f.id,
  d.name, d.slug, d.description,
  (SELECT id FROM coaching.sport WHERE key = 'fitness'),
  d.skill::public.skill_level,
  d.age_min,
  d.sets, d.reps, d.work, d.rest, d.est,
  TRUE, 'facility',
  d.summary, d.coach_lang, d.athlete_lang,
  d.family, d.phase_key, d.subrole, d.slot,
  d.req::jsonb, d.exec::jsonb, d.pairing::jsonb, d.media::jsonb
FROM (VALUES
  ('Half-Kneeling T-Spine Rotation Reach', 'half-kneeling-t-spine-rotation-reach', 'Opens thoracic rotation while the pelvis is constrained so throwers can rotate above a stable base instead of stealing motion from the low back.', 'BEGINNER', 8, 1, 6, 45, 15, 60, 'Half-Kneeling T-Spine Rotation Reach is a throwing-athlete exercise for opens thoracic rotation while the pelvis is constrained so throwers can rotate above a stable base instead of stealing motion from the low back.', 'Coach Half-Kneeling T-Spine Rotation Reach as throwing mobility, rib-scap access, and activation work. Use it when it supports the thrower''s kinetic chain without stealing quality from skill throwing, speed, or recovery.', 'Move clean, connect the ground to the hand, and stop before quality drops.', 'Thoracic rotation access', 'prepare_and_access', 'mobilize', 't_spine_rotation_access', '{"primary_joint_actions":["thoracic_rotation","hip_rotation","trunk_bracing"],"primary_tissues":["thoracic_spine","serratus_anterior","rotator_cuff","lats","hip_flexors"],"primary_motor_control_demands":[],"postural_shape":null,"breathing_demand":3,"balance_demand":4,"coordination_demand":2,"impact_level":0}'::jsonb, '{"movement_description":"Opens thoracic rotation while the pelvis is constrained so throwers can rotate above a stable base instead of stealing motion from the low back.","setup":["Select a clear space and set up mat.","Use a load, range, or speed that lets the athlete move without pain or compensation.","Confirm the athlete can breathe, brace, and keep neck, ribs, pelvis, and throwing-side shoulder organized before the first rep."],"execution_steps":["Move into the start position with ribs stacked over pelvis and shoulders relaxed.","Reach, rotate, or activate through a pain-free range while breathing calmly.","Own the end range briefly, then return with control.","Stop before fatigue, pinching, or range chasing changes the movement."],"coach_cues":["Breathe into the position.","Create usable range, not forced range.","Move the shoulder blade, not the neck."],"common_faults":["Forcing range.","Holding breath.","Shrugging, arching, or stealing motion from the low back."],"breathing_cues":["Exhale to set the ribs before effort.","Breathe between reps; do not hold your breath through setup and reset."],"quality_gate":"Rep passes only if the athlete gains or owns usable range without pain, breath-holding, or compensation.","stop_signs":["Pain, pinch, numbness, or tingling.","Loss of posture, balance, accuracy, or release speed.","Shoulder, elbow, or back compensation that does not correct with a cue."]}'::jsonb, '{"pairs_well_before":["throwing_skill","medicine_ball_output","strength_training","sport_practice"],"pairs_well_after":["general_warmup","breathing_or_rib_stack","hip_and_t_spine_access"],"good_for_sessions":["overhead_prep","sprint_prep","general_warmup","throwing_athlete_preparation"],"avoid_before":[],"avoid_after":[],"do_not_use_when":["sharp shoulder, elbow, back, hip, or wrist pain","mechanics already degraded from fatigue","throwing volume is being deliberately deloaded and the exercise adds the same stress"]}'::jsonb, '{"demo_video_sources":[],"coaching_articles":[],"clinical_or_sport_science_references":["Kinetic-chain reviews of overhead throwing and return-to-sport decision-making.","Resistance-training and medicine-ball training literature on throwing velocity and power transfer.","Shoulder-injury prevention and kinetic-chain strengthening literature for overhead athletes."],"internal_notes":["Use as support work; do not let the exercise compete with throwing skill quality or planned throwing-volume management."]}'::jsonb),
  ('Open Book T-Spine Rotation', 'open-book-t-spine-rotation', 'Restores gentle rib and thoracic rotation for athletes who feel locked up before throwing, batting, serving, or overhead work.', 'BEGINNER', 8, 1, 6, 45, 15, 60, 'Open Book T-Spine Rotation is a throwing-athlete exercise for restores gentle rib and thoracic rotation for athletes who feel locked up before throwing, batting, serving, or overhead work.', 'Coach Open Book T-Spine Rotation as throwing mobility, rib-scap access, and activation work. Use it when it supports the thrower''s kinetic chain without stealing quality from skill throwing, speed, or recovery.', 'Move clean, connect the ground to the hand, and stop before quality drops.', 'Thoracic rotation access', 'prepare_and_access', 'mobilize', 'open_book_rotation', '{"primary_joint_actions":["thoracic_rotation","hip_rotation","trunk_bracing"],"primary_tissues":["thoracic_spine","serratus_anterior","rotator_cuff","lats","hip_flexors"],"primary_motor_control_demands":[],"postural_shape":null,"breathing_demand":3,"balance_demand":2,"coordination_demand":2,"impact_level":0}'::jsonb, '{"movement_description":"Restores gentle rib and thoracic rotation for athletes who feel locked up before throwing, batting, serving, or overhead work.","setup":["Select a clear space and set up mat.","Use a load, range, or speed that lets the athlete move without pain or compensation.","Confirm the athlete can breathe, brace, and keep neck, ribs, pelvis, and throwing-side shoulder organized before the first rep."],"execution_steps":["Move into the start position with ribs stacked over pelvis and shoulders relaxed.","Reach, rotate, or activate through a pain-free range while breathing calmly.","Own the end range briefly, then return with control.","Stop before fatigue, pinching, or range chasing changes the movement."],"coach_cues":["Breathe into the position.","Create usable range, not forced range.","Move the shoulder blade, not the neck."],"common_faults":["Forcing ran